1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const LOYALTY_DISCOUNT_RATE = 0.2;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUM: Record<string, number> = {
8	  sword: 100,
9	  potion: 40,
10	  amulet: 60,
11	  staff: 80,
12	};
13	
14	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
17	
18	const totalBasePremium = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
20	
21	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
22	  items.filter(appliesTo).reduce((sum, item) => sum + itemBasePremium(item) * rate, 0);
23	
24	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
25	  const basePremium = totalBasePremium(items);
26	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
27	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
28	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
29	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
30	  return basePremium + cursedSurcharge + enchantmentSurcharge + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE;
31	}
32	
33	export function claim() {
34	  return undefined;
35	}
